import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { useAuth } from '../context/AuthContext';
import { authService } from '../services/stockService';
import { formatCurrency, getInitials } from '../utils/helpers';
import styles from './Profile.module.css';

export default function ProfilePage() {
  const { user, logout, updateBalance } = useAuth();
  const navigate = useNavigate();
  const [editing, setEditing] = useState(false);
  const [name,    setName]    = useState(user?.name || '');
  const [saving,  setSaving]  = useState(false);

  const handleSave = async () => {
    setSaving(true);
    try {
      await authService.updateProfile({ name });
      toast.success('Profile updated');
      setEditing(false);
    } catch { toast.error('Update failed'); }
    finally { setSaving(false); }
  };

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const memberSince = user?.createdAt
    ? new Date(user.createdAt).toLocaleDateString('en-IN', { month:'long', year:'numeric' })
    : 'Recently';

  return (
    <div className="fade-up" style={{ maxWidth:680 }}>
      <div className={styles.pageHead}>
        <h1 className={styles.title}>Profile</h1>
        <p className={styles.sub}>Account details &amp; settings</p>
      </div>

      {/* Profile card */}
      <div className={styles.profileCard}>
        <div className={styles.profileTop}>
          <div className={styles.avatar}>{getInitials(user?.name)}</div>
          <div className={styles.profileInfo}>
            {editing ? (
              <div className={styles.editRow}>
                <input
                  className={styles.nameInput}
                  value={name}
                  onChange={e => setName(e.target.value)}
                  autoFocus
                />
                <button className={styles.saveBtn} onClick={handleSave} disabled={saving}>
                  {saving ? 'Saving…' : 'Save'}
                </button>
                <button className={styles.cancelBtn} onClick={() => { setEditing(false); setName(user?.name||''); }}>Cancel</button>
              </div>
            ) : (
              <>
                <h2 className={styles.userName}>{user?.name}</h2>
                <p className={styles.userEmail}>✉️ {user?.email}</p>
              </>
            )}
          </div>
          {!editing && (
            <button className={styles.editBtn} onClick={() => setEditing(true)}>✏️ Edit</button>
          )}
        </div>
        <div className={styles.virtualBanner}>
          <span>🎉</span>
          <span>Virtual trading account — Practice with real NSE/BSE stocks, zero risk!</span>
        </div>
      </div>

      {/* Stats */}
      <div className={styles.statsGrid}>
        {[
          { icon:'💰', label:'Available Balance',  value: formatCurrency(user?.balance),        sub:'Ready to invest' },
          { icon:'📅', label:'Member Since',        value: memberSince,                          sub:'Registered' },
          { icon:'📊', label:'Total Stocks',        value: '50+',                               sub:'NSE/BSE listed' },
          { icon:'🚀', label:'IPO Tracker',         value: '9 IPOs',                            sub:'Tracked' },
        ].map(({ icon, label, value, sub }) => (
          <div key={label} className={styles.statCard}>
            <div className={styles.statIcon}>{icon}</div>
            <div>
              <div className={styles.statLabel}>{label}</div>
              <div className={styles.statValue}>{value}</div>
              <div className={styles.statSub}>{sub}</div>
            </div>
          </div>
        ))}
      </div>

      {/* Navigation shortcuts */}
      <div className={styles.linksCard}>
        <div className={styles.linksTitle}>Navigate</div>
        <div className={styles.linksGrid}>
          {[
            { icon:'💼', label:'Portfolio',      sub:'Holdings & P&L',  path:'/portfolio' },
            { icon:'📋', label:'Order History',  sub:'All trades',      path:'/orders'    },
            { icon:'⭐', label:'Watchlist',       sub:'Tracked stocks',  path:'/watchlist' },
            { icon:'🚀', label:'IPO Centre',     sub:'Open & Upcoming', path:'/ipo'       },
            { icon:'💰', label:'Mutual Funds',   sub:'SIP Calculator',  path:'/sip'       },
            { icon:'🌐', label:'Markets',         sub:'Nifty · Sensex',  path:'/market'    },
          ].map(({ icon, label, sub, path }) => (
            <div key={path} className={styles.linkItem} onClick={() => navigate(path)}>
              <span className={styles.linkIcon}>{icon}</span>
              <div>
                <div className={styles.linkLabel}>{label}</div>
                <div className={styles.linkSub}>{sub}</div>
              </div>
              <span className={styles.linkArrow}>→</span>
            </div>
          ))}
        </div>
      </div>

      {/* Logout */}
      <div className={styles.logoutCard}>
        <div>
          <div className={styles.logoutTitle}>Sign Out</div>
          <div className={styles.logoutSub}>You'll need to sign in again to access your account</div>
        </div>
        <button className={styles.logoutBtn} onClick={handleLogout}>🚪 Sign Out</button>
      </div>
    </div>
  );
}
